import React, { useState, useEffect } from 'react';
import axios from 'axios';

const TestConnection = () => {
  const [status, setStatus] = useState('Testing...');
  const [error, setError] = useState(null);

  useEffect(() => {
    const testConnection = async () => {
      try {
        const response = await axios.get('http://localhost:8080/api/tasks');
        setStatus('✅ Connected! Backend responding correctly');
        console.log('API Response:', response.data);
      } catch (err) {
        setStatus('❌ Connection Failed');
        setError(err.message);
        console.error('API Error:', err);
      }
    };

    testConnection();
  }, []);

  return (
    <div className="p-6">
      <div className="max-w-md mx-auto bg-white rounded-lg shadow p-6">
        <h2 className="text-xl font-bold text-gray-900 mb-4">API Connection Test</h2>

        <div className="space-y-4">
          <div className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
            <span className="text-sm font-medium text-gray-600">Status:</span>
            <span className={`text-lg font-bold ${status.includes('✅') ? 'text-green-600' : 'text-red-600'}`}>
              {status}
            </span>
          </div>

          {error && (
            <div className="p-4 bg-red-50 border border-red-200 rounded-lg">
              <h3 className="text-red-800 font-medium mb-2">Error Details:</h3>
              <p className="text-red-700">{error}</p>
            </div>
          )}

          <div className="p-4 bg-blue-50 border border-blue-200 rounded-lg">
            <h3 className="text-blue-800 font-medium mb-2">Next Steps:</h3>
            <ul className="list-disc list-inside text-blue-700 space-y-1">
              <li>If connection is successful, try accessing the main dashboard</li>
              <li>If connection fails, check if backend is running on port 8080</li>
              <li>Make sure CORS is properly configured</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TestConnection;
